var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"용병 아저씨들! 살아 있어요?","JPN":"傭兵のおじさんたち！　生きてます？","ENG":"Mr. Mercenaries! Are you guys still alive?","TWN":"傭兵大叔！你們還活著嗎？"},"stage":{"bg":"HANGAR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"저흰 아마 죽은 것 같지만요…… 부활 횟수가 얼마나 남았을까요?","JPN":"私たちは多分死んだみたいですけどね……復活回数はどのくらい残ってるんでしょうか？","ENG":"Although we seemed to be already dead... How many lives do you think we still have remaining?","TWN":"我們應該死了吧……還剩幾次可以復活？"},"stage":{"bg":"HANGAR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"어린 녀석들이 벌써부터 재수없는 소리 마!","JPN":"ガキのくせに縁起の悪いこというなよ！","ENG":"Hey! Don’t jinx us too!","TWN":"少說那些觸霉頭的話！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L6_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"그런데…… 어쩐지 처음 공격해오던 기세에 비해선 화력이 약해졌는걸?","JPN":"でも……なんか最初に攻撃してきた勢いに比べて火力が弱くなってねえか？","ENG":"Is it just me, or does it seem like their firepower has gotten weaker than when they first started attacking?","TWN":"不過……比起一開始的攻擊，現在的火力好像有減弱一點？"},"stage":{"bg":"HANGAR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"맞아. 어쩐지 총알이 묘하게 느리게 날아오는 것 같기도 하고.","JPN":"そう。なんだか銃弾が妙にのろく飛んできてるみたいな。","ENG":"You have a point. It’s like the bullets are flying slower than usual.","TWN":"對啊，很奇妙，子彈飛的速度好像也比較慢。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"그러고보니 분명 토미의 머리로 날아가던 총알이 살짝 휘어져서 이상한 곳으로 날아가던데?","JPN":"そういえば確かトミーの頭に飛んでった弾がちょっと曲がって変なとこに飛んでいったぞ？","ENG":"Now that I think about it, the bullet that was flying straight towards Tommy’s head slightly curved away from him.","TWN":"聽你這麼一說，原本瞄準湯米腦袋的子彈，好像也稍微飛歪欸？"},"stage":{"bg":"HANGAR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"뭔 헛소리야 그건? 총알이 눈에 보일 리 없잖아.","JPN":"なんだ、それ？　銃弾が目に見えるはずがねえだろ。","ENG":"Do you even hear what you’re saying? There’s no way you would’ve been able to see the bullet with your eyes.","TWN":"你在胡說八道什麼？肉眼怎麼可能看得到子彈！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"……과연, 그런 건가.","JPN":"……なるほど、そういうことか。","ENG":"Hmm... Could it be...","TWN":"……真是這樣嗎？"},"stage":{"bg":"HANGAR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"응? 뭔가 깨닫기라도 한 거야?","JPN":"うん？　なんか気付いたのか？","ENG":"Huh? Did you realize something?","TWN":"怎樣？你有什麼新的領悟嗎？"},"stage":{"bg":"HANGAR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"그동안 우리가 겪어온 죽음의 전장이 꽤 많았지.","JPN":"これまで俺たちは結構多くの死の戦場を経験してきたな。","ENG":"We have defied death on many battlefields throughout the years.","TWN":"我們至今不知道在戰場上經歷過多少次的生死關頭。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"그런 사선을 넘나드는 전투의 경험이 우리의 잠재력을 폭발 시킨 걸 수도 있어.","JPN":"そういう死線を越える戦闘経験が俺らの潜在力を爆発させたのかもしれねえ。","ENG":"All those experiences of treading the line between life and death may have awoken our potential.","TWN":"這種出生入死的戰鬥經驗，或許可以激發出我們的潛能。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"이른바…… <color=#ffd34c>각성</color>이란 녀석이지!","JPN":"いわゆる……<color=#ffd34c>覚醒</color>ってやつだ！","ENG":"Thus... We have achieved <color=#ffd34c>Awakening</color>!","TWN":"也就是所謂的……<color=#ffd34c>覺醒</color>！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"각성?","JPN":"覚醒？","ENG":"Awakening?","TWN":"覺醒？"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"각성!","JPN":"覚醒！","ENG":"Awakening!","TWN":"覺醒！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"가, 각성??","JPN":"か、覚醒？？","ENG":"A-awakening??","TWN":"覺…覺醒？？"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"각성! 각성!","JPN":"覚醒！　覚醒！","ENG":"Awakening! Awakening!","TWN":"覺醒！覺醒！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"그래! 우린 이제 각성 용병이 된 거야!","JPN":"そうだ！　俺らはこれで覚醒傭兵になったんだよ！","ENG":"Damn straight! We’ve become Awakened mercenaries!","TWN":"一定是這樣！我們現在是覺醒傭兵！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"좋아! 이 각성 제리가 놈들을 막아주겠어, 그 사이에 어서 함선으로 후퇴하라고 친구들!","JPN":"よし！　この覚醒ジェリーが奴らを止めてみせるぜ。その間に早く艦船に撤退しろよ、みんな！","ENG":"All right! I, Awakened Jerry, will hold them off! Everybody, head to the ship!","TWN":"很好！看我覺醒傑瑞怎麼擋下那些傢伙！朋友們，你們就趁機撤到艦船裡吧！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"우오오! 울어라 그란투리스모! 각성의 포효를!","JPN":"うおお！　鳴け、グランドツアー！　覚醒の咆哮だ！","ENG":"Hiyaaaaaa! Howl, Gran Turismo! Roar of Awakening!","TWN":"喔喔喔！來個覺醒的咆哮吧！格蘭多·里斯莫！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"………….","JPN":"……","ENG":"...","TWN":"…………"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"아까부터 왜 멍하니 허공에 팔을 젓고 있는 거야?","JPN":"さっきから何ボーっと宙に腕を振ってんだ？","ENG":"Why have you been standing there waving your arms in the air for the past few minutes?","TWN":"你從剛剛就在發什麼呆？"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"저 각성 용병 아저씨들이 적을 막는 동안 빨리 도망쳐야 해.","JPN":"あの覚醒傭兵のおじさんたちが敵を食い止めてるうちに早く逃げないと。","ENG":"We need to quickly escape while those Awakened mercenaries hold off the enemies.","TWN":"趁那些覺醒傭兵大叔在對付敵人，還不快逃！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"수리 중이던 엔터프라이즈에 탑승하면 안전할 거야!","JPN":"修理中のエンタープライズに乗れば安全なはずだ！","ENG":"We should be safe if we get on the Enterprise!","TWN":"搭上剛剛修理的企業號後應該就安全了！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"방해금지를 요청한다.","JPN":"妨害禁止を要請する。","ENG":"I request that you not interfere right now.","TWN":"請不要妨礙我。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"공간 장악 기능으로 적의 공격을 막는 건 연산량이 많이 필요한 작업이니까.","JPN":"空間掌握機能で敵の攻撃を防ぐことは、多くの演算量を必要とする作業なのだからな。","ENG":"Blocking the enemy’s attacks with my space domination function requires much calculation.","TWN":"利用空間掌握功能阻止敵人的攻擊，需要大量的演算作業。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"……뭐?","JPN":"……は？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"이봐, 들었어 앨버트? 넘버 5가 공간을 장악하는 중이라는데?","JPN":"おい、聞いた、アルバート？　ナンバー5が空間を掌握してるんだって。","ENG":"Hey, did you hear that Albert? Number 5 is dominating space right now.","TWN":"喂，亞伯特，你有聽到嗎？5號說她正在掌握空間中欸？"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"호오, 제법이군. 하지만 나는 이미 중학생 때 시간을 장악하고 있었지.","JPN":"ほう、やるね。でも私はもう中学生の時に時間を掌握したんだよ。","ENG":"Oh, that’s impressive. However, I’ve been dominating time since I was in middle school.","TWN":"哎唷，不錯喔！不過我國中時就已經掌握時間咧？"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"하지만 넘버 5, 기억해 둬. 네가 거머쥐어야 할 건 모두와의 소중한 우정이야.","JPN":"でもナンバー5、覚えておいて。あなたが握るべきものはみんなとの大事な友情なんだ。","ENG":"However, remember this, Number 5. What you really need to hold on to is the precious friendships that you have with everyone.","TWN":"5號，你記住，你該抓住的，是和大家之間珍貴的友情！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"그래 그러니까 이상한 컨셉은 관두고 빨리 도망치자고!","JPN":"そう、だからその変なコンセプトはやめて早く逃げようって！","ENG":"Okay, I got it, so drop the weird vibes and let’s get out of here!","TWN":"沒錯，所以不要再想那些有的沒的，逃命要緊！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"………….","JPN":"……","ENG":"...","TWN":"…………"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_TECH_12"}]`);export{e as default};